--
-- TOC entry 230 (class 1259 OID 16682)
-- Name: agent_performance_summary; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.agent_performance_summary AS
 SELECT u.id AS agent_id,
    u.name AS agent_name,
    u."employeeId" AS employee_id,
    u.email,
    d.name AS department_name,
    count(DISTINCT c.id) AS total_cases_assigned,
    count(DISTINCT
        CASE
            WHEN ((c.status)::text = ANY (ARRAY[('COMPLETED'::character varying)::text, ('APPROVED'::character varying)::text])) THEN c.id
            ELSE NULL::uuid
        END) AS cases_completed,
    count(DISTINCT fs.id) AS total_forms_submitted,
    count(DISTINCT
        CASE
            WHEN ((fs.form_type)::text = 'RESIDENCE'::text) THEN fs.id
            ELSE NULL::uuid
        END) AS residence_forms_submitted,
    count(DISTINCT
        CASE
            WHEN ((fs.form_type)::text = 'OFFICE'::text) THEN fs.id
            ELSE NULL::uuid
        END) AS office_forms_submitted,
    count(DISTINCT
        CASE
            WHEN ((fs.form_type)::text = 'BUSINESS'::text) THEN fs.id
            ELSE NULL::uuid
        END) AS business_forms_submitted,
    avg(fqm.overall_quality_score) AS avg_quality_score,
    avg((EXTRACT(epoch FROM (c."updatedAt" - c."createdAt")) / (86400)::numeric)) AS avg_completion_days,
    count(DISTINCT a.id) AS attachments_uploaded,
    max(u.last_active_at) AS last_active_at
   FROM (((((public.users u
     LEFT JOIN public.departments d ON ((u."departmentId" = d.id)))
     LEFT JOIN public.cases c ON ((c."assignedTo" = u.id)))
     LEFT JOIN public.form_submissions fs ON ((fs.submitted_by = u.id)))
     LEFT JOIN public.form_quality_metrics fqm ON ((fs.id = fqm.form_submission_id)))
     LEFT JOIN public.attachments a ON ((a."uploadedBy" = u.id)))
  WHERE ((u.role)::text = 'FIELD_AGENT'::text)
  GROUP BY u.id, u.name, u."employeeId", u.email, d.name;


ALTER VIEW public.agent_performance_summary OWNER TO acs_user;

