--
-- TOC entry 250 (class 1259 OID 16809)
-- Name: case_completion_analytics; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.case_completion_analytics AS
 SELECT c.id,
    c."caseId",
    c."customerName",
    c.status,
    c.priority,
    c."assignedTo",
    u.name AS agent_name,
    u."employeeId" AS employee_id,
    cl.name AS client_name,
    c.form_completion_percentage,
    c.quality_score,
    c.forms_submitted_count,
    c.total_forms_required,
    count(DISTINCT fs.id) AS actual_forms_submitted,
    count(DISTINCT
        CASE
            WHEN ((fs.validation_status)::text = 'VALID'::text) THEN fs.id
            ELSE NULL::uuid
        END) AS valid_forms,
    count(DISTINCT a.id) AS attachment_count,
    (EXTRACT(epoch FROM (c."updatedAt" - c."createdAt")) / (86400)::numeric) AS completion_days,
    c."createdAt",
    c."updatedAt"
   FROM ((((public.cases c
     LEFT JOIN public.users u ON ((c."assignedTo" = u.id)))
     LEFT JOIN public.clients cl ON ((c."clientId" = cl.id)))
     LEFT JOIN public.form_submissions fs ON ((fs.case_id = c.id)))
     LEFT JOIN public.attachments a ON ((a.case_id = c.id)))
  GROUP BY c.id, c."caseId", c."customerName", c.status, c.priority, c."assignedTo", u.name, u."employeeId", cl.name, c.form_completion_percentage, c.quality_score, c.forms_submitted_count, c.total_forms_required, c."createdAt", c."updatedAt";


ALTER VIEW public.case_completion_analytics OWNER TO acs_user;

