--
-- TOC entry 272 (class 1259 OID 16919)
-- Name: fieldAgentTerritories; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public."fieldAgentTerritories" AS
 SELECT u.id AS "userId",
    u.name AS "userName",
    u.username,
    u."employeeId",
    upa.id AS "pincodeAssignmentId",
    p.id AS "pincodeId",
    p.code AS "pincodeCode",
    c.name AS "cityName",
    s.name AS "stateName",
    co.name AS "countryName",
    COALESCE(json_agg(json_build_object('areaAssignmentId', uaa.id, 'areaId', a.id, 'areaName', a.name, 'assignedAt', uaa."assignedAt") ORDER BY a.name) FILTER (WHERE (a.id IS NOT NULL)), '[]'::json) AS "assignedAreas",
    upa."assignedAt" AS "pincodeAssignedAt",
    upa."assignedBy",
    upa."isActive"
   FROM (((((((public.users u
     JOIN public."userPincodeAssignments" upa ON ((u.id = upa."userId")))
     JOIN public.pincodes p ON ((upa."pincodeId" = p.id)))
     JOIN public.cities c ON ((p."cityId" = c.id)))
     JOIN public.states s ON ((c."stateId" = s.id)))
     JOIN public.countries co ON ((c."countryId" = co.id)))
     LEFT JOIN public."userAreaAssignments" uaa ON (((upa.id = uaa."userPincodeAssignmentId") AND (uaa."isActive" = true))))
     LEFT JOIN public.areas a ON ((uaa."areaId" = a.id)))
  WHERE (upa."isActive" = true)
  GROUP BY u.id, u.name, u.username, u."employeeId", upa.id, p.id, p.code, c.name, s.name, co.name, upa."assignedAt", upa."assignedBy", upa."isActive";


ALTER VIEW public."fieldAgentTerritories" OWNER TO acs_user;

--
-- TOC entry 5779 (class 0 OID 0)
-- Dependencies: 272
-- Name: VIEW "fieldAgentTerritories"; Type: COMMENT; Schema: public; Owner: acs_user
--

COMMENT ON VIEW public."fieldAgentTerritories" IS 'Comprehensive view of field agent territory assignments with pincode and area details';


--
-- TOC entry 273 (class 1259 OID 16924)
-- Name: field_agent_workload; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.field_agent_workload AS
 SELECT u.id AS user_id,
    u.name AS agent_name,
    u.email AS agent_email,
    count(c.id) AS total_assigned_cases,
    count(
        CASE
            WHEN ((c.status)::text = 'ASSIGNED'::text) THEN 1
            ELSE NULL::integer
        END) AS pending_cases,
    count(
        CASE
            WHEN ((c.status)::text = 'IN_PROGRESS'::text) THEN 1
            ELSE NULL::integer
        END) AS in_progress_cases,
    count(
        CASE
            WHEN ((c.status)::text = 'COMPLETED'::text) THEN 1
            ELSE NULL::integer
        END) AS completed_cases,
    max(cah."assignedAt") AS last_assignment_date,
    count(
        CASE
            WHEN (cah."assignedAt" >= (now() - '7 days'::interval)) THEN 1
            ELSE NULL::integer
        END) AS assignments_last_7_days
   FROM ((public.users u
     LEFT JOIN public.cases c ON ((u.id = c."assignedTo")))
     LEFT JOIN public.case_assignment_history cah ON ((u.id = cah."toUserId")))
  WHERE (((u.role)::text = 'FIELD_AGENT'::text) AND (u."isActive" = true))
  GROUP BY u.id, u.name, u.email
  ORDER BY (count(c.id)) DESC;


ALTER VIEW public.field_agent_workload OWNER TO acs_user;

