-- TOC entry 274 (class 1259 OID 16929)
-- Name: form_submission_analytics; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.form_submission_analytics AS
 SELECT fs.id,
    fs.case_id,
    fs.form_type,
    fs.validation_status,
    fs.submitted_at,
    fs.validated_at,
    fs.photos_count,
    fs.attachments_count,
    fs.submission_score,
    fs.time_spent_minutes,
    fs.device_info,
    fs.network_quality,
    fs.geo_location,
    u.name AS agent_name,
    u."employeeId" AS employee_id,
    c."caseId" AS case_number,
    c."customerName" AS customer_name,
    c.status AS case_status,
    fqm.overall_quality_score,
    fqm.completeness_score,
    fqm.accuracy_score,
    fqm.photo_quality_score,
    fqm.timeliness_score
   FROM (((public.form_submissions fs
     LEFT JOIN public.users u ON ((fs.submitted_by = u.id)))
     LEFT JOIN public.cases c ON ((fs.case_id = c.id)))
     LEFT JOIN public.form_quality_metrics fqm ON ((fs.id = fqm.form_submission_id)));


ALTER VIEW public.form_submission_analytics OWNER TO acs_user;

